import torch
import torch.nn.functional as F


# CUDA C++ persistent grid-stride kernel with explicit float4 vectorization.
# Grid-sized to fill all SMs, each CTA claims work via grid-stride loop.
# Eliminates launch overhead and targets HBM bandwidth ceiling (~85-95% of achievable BW).
@torch.no_grad()
def run(
    grad_q_embed: torch.Tensor,
    grad_k_embed: torch.Tensor,
    q: torch.Tensor,
    k: torch.Tensor,
    embeddings: torch.Tensor,
):
    if seq_len <= 0:
        return (
            torch.empty_like(q),
            torch.empty_like(k),
            torch.empty_like(embeddings),
        )

    half = head_dim // 2
    block_s = 64

    # Grid over seq_len, sized to 148 SMs for minimal launch overhead
    grid_size = min(148, (seq_len + block_s - 1) // block_s + 1)

    _rope_backward_kernel[grid_size](
        grad_q_embed,
        grad_k_embed,
        q,
        k,
        embeddings,
        grad_q,
        grad_k,
        grad_embeddings,
        seq_len,
        num_heads=num_heads,
        half=half,
        head_dim=head_dim,
        block_s=block_s,
    )

    return grad_q, grad_k, grad_embeddings


# CUDA C++ kernel (sm_100) - persistent grid-stride with float4
__global__ void _rope_backward_kernel(
    const float* __restrict__ grad_q_embed,
    const float* __restrict__ grad_k_embed,
    const float* __restrict__ q,
    const float* __restrict__ k,
    const float* __restrict__ embeddings,
    float* __restrict__ grad_q,
    float* __restrict__ grad_k,
    float* __restrict__ grad_embeddings,
    int seq_len,
    int num_heads,
    int half,
    int head_dim,
    int block_s,
) {
    // Persistent grid-stride loop
    int s = blockIdx.x * block_s + threadIdx.x;
    for (; s < seq_len; s += block_s * blockDim.x) {
        // Load embeddings using float4
        float4 emb0 = __ldg(embeddings + s * head_dim);
        float4 emb1 = __ldg(embeddings + s * head_dim + half);

        float c0[4], s0[4], c1[4], s1[4];
        sincosf(emb0.x, &s0[0], &c0[0]);
        sincosf(emb0.y, &s0[1], &c0[1]);
        sincosf(emb0.z, &s0[2], &c0[2]);
        sincosf(emb0.w, &s0[3], &c0[3]);
        sincosf(emb1.x, &s1[0], &c1[0]);
        sincosf(emb1.y, &s1[1], &c1[1]);
        sincosf(emb1.z, &s1[2], &c1[2]);
        sincosf(emb1.w, &s1[3], &c1[3]);

        // Process all 16 heads
        #pragma unroll
        for (int h = 0; h < num_heads; h++) {
            int base = s * head_dim * num_heads + h * head_dim;

            float4 q_val = __ldg(q + base);
            float4 k_val = __ldg(k + base);
            float4 grad_q_embed_val = __ldg(grad_q_embed + base);
            float4 grad_k_embed_val = __ldg(grad_k_embed + base);

            // Rotate half: [x0,x1,x2,x3] -> [-x3,x0,x1,x2]
            float4 q_rot, k_rot;
            q_rot.x = -q_val.w; q_rot.y = q_val.x; q_rot.z = q_val.y; q_rot.w = q_val.z;
            k_rot.x = -k_val.w; k_rot.y = k_val.x; k_rot.z = k_val.y; k_rot.w = k_val.z;

            // Gradient rotation backward: [g0,g1,g2,g3] -> [g3,-g0,-g1,-g2]
            float4 grad_q_rot, grad_k_rot;
            grad_q_rot.x = grad_q_embed_val.w;
            grad_q_rot.y = -grad_q_embed_val.x;
            grad_q_rot.z = -grad_q_embed_val.y;
            grad_q_rot.w = grad_q_embed_val.z;
            grad_k_rot.x = grad_k_embed_val.w;
            grad_k_rot.y = -grad_k_embed_val.x;
            grad_k_rot.z = -grad_k_embed_val.y;
            grad_k_rot.w = grad_k_embed_val.z;

            // grad_q = g * cos + rotate_half_backward(g * sin)
            float4 grad_q;
            grad_q.x = grad_q_embed_val.x * c0[0] + grad_q_rot.x * s0[0];
            grad_q.y = grad_q_embed_val.y * c0[1] + grad_q_rot.y * s0[1];
            grad_q.z = grad_q_embed_val.z * c0[2] + grad_q_rot.z * s0[2];
            grad_q.w = grad_q_embed_val.w * c0[3] + grad_q_rot.w * s0[3];
            __stwt(grad_q + base, grad_q);

            // grad_k (same pattern)
            float4 grad_k;
            grad_k.x = grad_k_embed_val.x * c0[0] + grad_k_rot.x * s0[0];
            grad_k.y = grad_k_embed_val.y * c0[1] + grad_k_rot.y * s0[1];
            grad_k.z = grad_k_embed_val.z * c0[2] + grad_k_rot.z * s0[2];
            grad_k.w = grad_k_embed_val.w * c0[3] + grad_k_rot.w * s0[3];
            __stwt(grad_k + base, grad_k);

            // Gradient w.r.t. embeddings (sum over all heads)
            float sum_cos0 = q_val.x * grad_q_embed_val.x + q_val.y * grad_q_embed_val.y +
                            q_val.z * grad_q_embed_val.z + q_val.w * grad_q_embed_val.w;
            float sum_sin0 = -q_rot.x * grad_q_embed_val.x - q_rot.y * grad_q_embed_val.y -
                            q_rot.z * grad_q_embed_val.z - q_rot.w * grad_q_embed_val.w;
            float sum_cos1 = q_val.w * grad_q_embed_val.w + q_val.x * grad_q_embed_val.x +
                            q_val.y * grad_q_embed_val.y + q_val.z * grad_q_embed_val.z;
            float sum_sin1 = q_rot.x * grad_q_embed_val.w + q_rot.y * grad_q_embed_val.x +
                            q_rot.z * grad_q_embed_val.y + q_rot.w * grad_q_embed_val.z;

            float sum_cos2 = k_val.x * grad_k_embed_val.x + k_val.y * grad_k_embed_val.y +
                            k_val.z * grad_k_embed_val.z + k_val.w * grad_k_embed_val.w;
            float sum_sin2 = -k_rot.x * grad_k_embed_val.x - k_rot.y * grad_k_embed_val.y -
                            k_rot.z * grad_k_embed_val.z - k_rot.w * grad_k_embed_val.w;
            float sum_cos3 = k_val.w * grad_k_embed_val.w + k_val.x * grad_k_embed_val.x +
                            k_val.y * grad_k_embed_val.y + k_val.z * grad_k_embed_val.z;
            float sum_sin3 = k_rot.x * grad_k_embed_val.w + k_rot.y * grad_k_embed_val.x +
                            k_rot.z * grad_k_embed_val.y + k_rot.w * grad_k_embed_val.z;

            // Backprop through cos/sin
            float4 grad_emb0, grad_emb1;
            grad_emb0.x = -s0[0] * (sum_cos0 + sum_cos2) + c0[0] * sum_sin0;
            grad_emb0.y = -s0[1] * (sum_cos0 + sum_cos2) + c0[1] * sum_sin0;
            grad_emb0.z = -s0[2] * (sum_cos0 + sum_cos2) + c0[2] * sum_sin0;
            grad_emb0.w = -s0[3] * (sum_cos0 + sum_cos2) + c0[3] * sum_sin0;
            __stwt(grad_embeddings + s * head_dim, grad_emb0);

            grad_emb1.x = -s1[0] * (sum_cos1 + sum_cos3) + c1[0] * sum_sin1;
            grad_emb1.y = -s1[1] * (sum_cos1 + sum_cos3) + c1[1] * sum_sin1;
            grad_emb1.z = -s1[2] * (sum_cos1 + sum_cos3) + c1[2] * sum_sin1;
            grad_emb1.w = -s1[3] * (sum_cos1 + sum_cos3) + c1[3] * sum_sin1;
            __stwt(grad_embeddings + s * head_dim + half, grad_emb1);
        }
    }
}
